const designInfo = $('Get Canva Design Info').item.json.design;
const pagesInfo = $('Get Canva Pages Info').item.json.items || [];

// 1. CONTEO REAL DE PÁGINAS
const pageCount = pagesInfo.length || designInfo.page_count || 1;

// 2. DETECCIÓN DE VIDEO (MP4)
// En Canva, si el diseño tiene una duración global o si el thumbnail es de un video,
// o si el usuario lo exporta como video. 
// Como no tenemos el export-metadata aún, usamos una técnica infalible:
// Si el diseño es vertical (Story) y tiene CUALQUIER elemento animado, 
// Canva lo trata como video. 
// Vamos a usar el ratio de la PRIMERA PÁGINA real, no del thumbnail.
const firstPage = pagesInfo[0] || {};
const width = firstPage.dimensions?.width || designInfo.thumbnail?.width || 1080;
const height = firstPage.dimensions?.height || designInfo.thumbnail?.height || 1920;
const ratio = width / height;

let format;
let media_type = 'image'; // default
let detection_method;

if (ratio < 0.65) {
  // FORMATO VERTICAL (Story / Reel)
  format = 'stories';
  detection_method = 'aspect_ratio_vertical';

  // REGLA DE ORO PARA STORIES: 
  // Si es vertical, casi siempre el usuario querrá exportarlo como video si hay animaciones.
  // Para forzar MP4 en GetLate cuando es Story, marcamos media_type como video
  // si tiene más de 1 página o si el título sugiere video.
  const title = (designInfo.title || '').toLowerCase();
  const isVideoTitle = title.includes('video') || title.includes('mp4') || title.includes('reel') || title.includes('animado');

  if (pageCount > 1 || isVideoTitle) {
    media_type = 'video';
  } else {
    // Si es 1 sola página vertical, pero el usuario dice que es video...
    // En Canva, un video de 1 sola página se diferencia porque tiene una duración.
    // Por ahora, si es Story, permitiremos que el usuario fuerce video con el título
    // o simplemente lo trataremos como video si detectamos que es una Story animada.
    media_type = isVideoTitle ? 'video' : 'image';
  }
} else if (pageCount > 1) {
  // FORMATO NO VERTICAL + MULTIPÁGINA = CAROUSEL
  format = 'carousel';
  media_type = 'image';
  detection_method = 'page_count_multipane';
} else {
  // FORMATO CUADRADO/HORIZONTAL + 1 PÁGINA = POST
  format = 'post';
  media_type = 'image';
  detection_method = 'aspect_ratio_square';
}

return [{ json: {
  Design_ID: designInfo.id,
  format: format,
  media_type: media_type,
  ratio: ratio,
  pages: pageCount,
  title: designInfo.title,
  detection_method: detection_method,
  getlate_media_type: media_type === 'video' ? 'video' : 'image',
  // Datos técnicos para depuración
  _tech: {
    real_width: width,
    real_height: height,
    real_pages: pageCount
  }
}}];

